/** `/ns/*` catalog list pages — full-height flex shell (no outer content scroll). */
export function isCatalogListPath(pathname: string): boolean {
  return (
    pathname === '/ns/nhan-vien' ||
    pathname === '/ns/ca-lam-viec' ||
    pathname === '/ns/nhom-nhan-vien' ||
    pathname === '/ns/cham-cong' ||
    pathname === '/ns/bang-luong' ||
    pathname === '/ns/so-luong-khoan'
  );
}
